/**
 * migrate-json-to-po.mjs
 *
 * Migrates existing translations from Lingui v3/v4 "minimal" JSON format
 * (translation.json) into the newly generated Lingui v5 PO files
 * (translation.po) where all msgstr values are empty.
 *
 * For each non-source locale:
 *   1. Reads translation.json  (key = msgid, value = translated string)
 *   2. Reads translation.po    (generated by `lingui extract`, msgstr all empty)
 *   3. Matches each PO msgid to a JSON key (accounting for PO quote escaping)
 *   4. Writes the translated msgstr into the PO file
 *
 * Usage:
 *   node scripts/migrate-json-to-po.mjs
 */

import { readFileSync, writeFileSync, readdirSync, statSync } from "node:fs";
import { join } from "node:path";

const LOCALES_DIR = new URL(
  "../src/i18n/locales",
  import.meta.url
).pathname;

/** Source locale -- already has msgstr == msgid, skip it. */
const SOURCE_LOCALE = "en";

/**
 * Unescape a PO-encoded string to recover the literal message ID.
 *
 * Inside a PO quoted value (`msgid "..."` / `msgstr "..."`), the only
 * escaping that affects our matching is:
 *   - `\"` -> literal `"`
 *   - `\\` -> literal `\`
 *   - `\n` -> literal newline (not expected here, but handled)
 *   - `\t` -> literal tab      (not expected here, but handled)
 *
 * @param {string} raw  The content captured between the outer quotes of a
 *                       `msgid "..."` line (i.e. without the surrounding `"`).
 * @returns {string}     The unescaped string suitable for lookup in the JSON map.
 */
function unescapePo(raw) {
  let result = "";
  for (let i = 0; i < raw.length; i++) {
    if (raw[i] === "\\" && i + 1 < raw.length) {
      const next = raw[i + 1];
      switch (next) {
        case '"':
          result += '"';
          i++;
          break;
        case "\\":
          result += "\\";
          i++;
          break;
        case "n":
          result += "\n";
          i++;
          break;
        case "t":
          result += "\t";
          i++;
          break;
        default:
          // Unknown escape -- keep as-is
          result += raw[i];
          break;
      }
    } else {
      result += raw[i];
    }
  }
  return result;
}

/**
 * Escape a translation string for insertion into a PO `msgstr "..."` line.
 *
 * The inverse of {@link unescapePo}:
 *   - literal `\` -> `\\`
 *   - literal `"` -> `\"`
 *   - literal newline -> `\n`
 *   - literal tab -> `\t`
 *
 * @param {string} value  The plain-text translation from the JSON file.
 * @returns {string}      PO-safe string that can go between double quotes.
 */
function escapePo(value) {
  return value
    .replace(/\\/g, "\\\\")
    .replace(/"/g, '\\"')
    .replace(/\n/g, "\\n")
    .replace(/\t/g, "\\t");
}

/**
 * Parse a PO file and return a structured representation of its entries
 * that can be round-tripped (preserving comments, blank lines, etc.).
 *
 * The returned array contains objects of the form:
 *   { type: "entry", comments: string[], msgid: string, msgstr: string, rawMsgidLine: string, rawMsgstrLine: string }
 *   { type: "header", lines: string[] }
 *   { type: "other", line: string }
 *
 * We deliberately keep parsing minimal -- we only need single-line msgid/msgstr
 * entries (which is the format Lingui v5 `extract` produces for this project).
 *
 * @param {string} content  Full text content of a .po file.
 * @returns {{ lines: string[], entries: Map<string, number> }}
 *   - lines:   the file split into lines (mutable in-place)
 *   - entries: map from *unescaped* msgid -> line index of the corresponding msgstr line
 */
function parsePo(content) {
  const lines = content.split("\n");

  /** @type {Map<string, number>} unescaped msgid -> index of msgstr line */
  const entries = new Map();

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // Match `msgid "..."` (single-line, non-empty)
    if (line.startsWith('msgid "') && line.endsWith('"') && line.length > 8) {
      const rawMsgid = line.slice(7, -1); // content between outer quotes
      const unescapedMsgid = unescapePo(rawMsgid);

      // The next non-blank, non-comment line should be `msgstr "..."`
      let j = i + 1;
      while (j < lines.length && !lines[j].startsWith("msgstr ")) {
        j++;
      }
      if (j < lines.length && lines[j].startsWith('msgstr "')) {
        entries.set(unescapedMsgid, j);
      }
    }
  }

  return { lines, entries };
}

/**
 * Process a single locale directory.
 *
 * @param {string} locale  The locale code (directory name).
 * @returns {{ matched: number, skipped: number, total: number }}
 */
function processLocale(locale) {
  const localeDir = join(LOCALES_DIR, locale);
  const jsonPath = join(localeDir, "translation.json");
  const poPath = join(localeDir, "translation.po");

  // ---------- Load JSON translations ----------
  let jsonData;
  try {
    const jsonContent = readFileSync(jsonPath, "utf-8");
    jsonData = JSON.parse(jsonContent);
  } catch (err) {
    console.warn(`  [WARN] Could not read ${jsonPath}: ${err.message}`);
    return { matched: 0, skipped: 0, total: 0 };
  }

  // ---------- Load PO file ----------
  let poContent;
  try {
    poContent = readFileSync(poPath, "utf-8");
  } catch (err) {
    console.warn(`  [WARN] Could not read ${poPath}: ${err.message}`);
    return { matched: 0, skipped: 0, total: 0 };
  }

  const { lines, entries } = parsePo(poContent);

  let matched = 0;
  let skipped = 0;
  const total = entries.size;

  for (const [msgid, msgstrLineIdx] of entries) {
    const translation = jsonData[msgid];

    // No translation available in JSON, or translation is an empty string
    if (translation === undefined || translation === null) {
      skipped++;
      continue;
    }

    // Skip array values (ICU compiled forms) -- though we confirmed there are none
    if (Array.isArray(translation)) {
      skipped++;
      continue;
    }

    // Skip empty translations (untranslated in JSON too)
    if (typeof translation === "string" && translation === "") {
      skipped++;
      continue;
    }

    if (typeof translation !== "string") {
      console.warn(
        `  [WARN] Unexpected value type for "${msgid}": ${typeof translation}`
      );
      skipped++;
      continue;
    }

    // Build the new msgstr line
    const escapedTranslation = escapePo(translation);
    lines[msgstrLineIdx] = `msgstr "${escapedTranslation}"`;
    matched++;
  }

  // ---------- Write updated PO file ----------
  const updatedContent = lines.join("\n");
  writeFileSync(poPath, updatedContent, "utf-8");

  return { matched, skipped, total };
}

// =============================================================================
// Main
// =============================================================================

console.log("=== Lingui JSON -> PO Migration ===\n");
console.log(`Locales directory: ${LOCALES_DIR}`);
console.log(`Source locale (skipped): ${SOURCE_LOCALE}\n`);

const localeDirs = readdirSync(LOCALES_DIR).filter((entry) => {
  const fullPath = join(LOCALES_DIR, entry);
  return statSync(fullPath).isDirectory();
});

console.log(`Found ${localeDirs.length} locale directories.\n`);

let totalMatched = 0;
let totalSkipped = 0;
let totalEntries = 0;
let localesProcessed = 0;

for (const locale of localeDirs.sort()) {
  if (locale === SOURCE_LOCALE) {
    console.log(`[${locale}] Skipped (source locale)`);
    continue;
  }

  const { matched, skipped, total } = processLocale(locale);
  console.log(
    `[${locale}] ${matched}/${total} msgstr populated, ${skipped} skipped (no translation or empty)`
  );

  totalMatched += matched;
  totalSkipped += skipped;
  totalEntries += total;
  localesProcessed++;
}

console.log("\n=== Summary ===");
console.log(`Locales processed: ${localesProcessed}`);
console.log(`Total PO entries across all locales: ${totalEntries}`);
console.log(`Total msgstr populated: ${totalMatched}`);
console.log(`Total skipped (no JSON match or empty): ${totalSkipped}`);
console.log("\nDone.");
